import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        ArrayList<Mermaid> mermaids = new ArrayList<>();
        mermaids.add(new Mermaid("Ariel",  "Atlantic"));
        mermaids.add(new Mermaid("Marina", "Pacific"));
        mermaids.add(new Mermaid("Coral",  "Atlantic"));
        mermaids.add(new Mermaid("Pearl",  "Indian"));
        mermaids.add(new Mermaid("Cleo",   "Pacific"));

        ArrayList<Submarine> subs = new ArrayList<>();
        subs.add(new Submarine("Nautilus",     400));
        subs.add(new Submarine("Deep Explorer",800));
        subs.add(new Submarine("Sea Voyager",  300));
        subs.add(new Submarine("Mariana",     1000));

        // в”Ђв”Ђ (1) Atlantic mermaids в”Ђв”Ђ
        List<String> atlanticNames = mermaids.stream()
            .filter(m -> m.getOcean().equals("Atlantic"))
            .map(m -> m.getName())
            .collect(Collectors.toList());
        checkBool("Atlantic count is 2", true, atlanticNames.size() == 2);
        checkBool("Atlantic contains Ariel", true, atlanticNames.contains("Ariel"));
        checkBool("Atlantic contains Coral", true, atlanticNames.contains("Coral"));
        checkBool("Atlantic does NOT contain Marina", false, atlanticNames.contains("Marina"));

        // в”Ђв”Ђ (2) Deep submarines (maxDepth > 500) в”Ђв”Ђ
        List<String> deepNames = subs.stream()
            .filter(s -> s.getMaxDepth() > 500)
            .map(s -> s.getName())
            .collect(Collectors.toList());
        checkBool("Deep sub count is 2", true, deepNames.size() == 2);
        checkBool("Deep contains Deep Explorer", true, deepNames.contains("Deep Explorer"));
        checkBool("Deep contains Mariana",       true, deepNames.contains("Mariana"));
        checkBool("Deep does NOT contain Nautilus", false, deepNames.contains("Nautilus"));

        // в”Ђв”Ђ (3) Names starting with C в”Ђв”Ђ
        List<String> cNames = mermaids.stream()
            .filter(m -> m.getName().startsWith("C"))
            .map(m -> m.getName())
            .collect(Collectors.toList());
        checkBool("C-names count is 2", true, cNames.size() == 2);
        checkBool("C-names contains Coral", true, cNames.contains("Coral"));
        checkBool("C-names contains Cleo",  true, cNames.contains("Cleo"));
        checkBool("C-names does NOT contain Ariel", false, cNames.contains("Ariel"));

        // в”Ђв”Ђ (4) Shallow subs (maxDepth <= 400) в”Ђв”Ђ
        List<String> shallowNames = subs.stream()
            .filter(s -> s.getMaxDepth() <= 400)
            .map(s -> s.getName())
            .collect(Collectors.toList());
        checkBool("Shallow count is 2", true, shallowNames.size() == 2);
        checkBool("Shallow contains Nautilus",  true, shallowNames.contains("Nautilus"));
        checkBool("Shallow contains Sea Voyager",true, shallowNames.contains("Sea Voyager"));
        checkBool("Shallow does NOT contain Mariana", false, shallowNames.contains("Mariana"));

        // в”Ђв”Ђ summary в”Ђв”Ђ
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected " + expected + " but got " + actual); failed++;
        }
    }
}
